import React, { useState, useEffect } from "react";
import axios from "axios";

const BlogManage = () => {
  const [blogs, setBlogs] = useState([]);
  const [form, setForm] = useState({
    title: "",
    full_content: "",
    user_id: "",
    category_id: "",
  });
  const [imageFile, setImageFile] = useState(null); // for file upload
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Fetch blogs
  const fetchBlogs = async () => {
    setLoading(true);
    setError("");
    try {
      const token = localStorage.getItem("token");
      const config = token
        ? { headers: { Authorization: `Bearer ${token}` } }
        : {};
      const res = await axios.get("http://localhost:5000/api/blogs", config);
      setBlogs(res.data);
    } catch (err) {
      setError("Failed to fetch blogs.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBlogs();
  }, []);

  // Handle text input changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  // Handle file selection
  const handleFileChange = (e) => {
    setImageFile(e.target.files[0]);
  };

  // Submit form data (add or update)
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const token = localStorage.getItem("token");
      const config = {
        headers: {
          Authorization: token ? `Bearer ${token}` : "",
          "Content-Type": "multipart/form-data",
        },
      };

      // Prepare form data for file upload
      const formData = new FormData();
      formData.append("title", form.title);
      formData.append("full_content", form.full_content);
      formData.append("user_id", Number(form.user_id));
      formData.append("category_id", Number(form.category_id));
      if (imageFile) {
        formData.append("image", imageFile);
      }

      if (editId) {
        await axios.put(`http://localhost:5000/api/blogs/${editId}`, formData, config);
        setEditId(null);
      } else {
        await axios.post("http://localhost:5000/api/blogs", formData, config);
      }

      setForm({
        title: "",
        full_content: "",
        user_id: "",
        category_id: "",
      });
      setImageFile(null);
      await fetchBlogs();
    } catch (err) {
      setError(
        err.response?.data?.message || "Failed to save blog. Check console."
      );
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // Fill form for editing
  const handleEdit = (blog) => {
    setForm({
      title: blog.title,
      full_content: blog.full_content || "",
      user_id: blog.user_id.toString(),
      category_id: blog.category_id.toString(),
    });
    setImageFile(null); // clear file input for edit
    setEditId(blog.id);
  };

  // Delete blog
  const handleDelete = async (id) => {
    if (!window.confirm("Delete this blog?")) return;
    setLoading(true);
    setError("");

    try {
      const token = localStorage.getItem("token");
      const config = token
        ? { headers: { Authorization: `Bearer ${token}` } }
        : {};
      await axios.delete(`http://localhost:5000/api/blogs/${id}`, config);
      await fetchBlogs();
    } catch (err) {
      setError(
        err.response?.data?.message || "Failed to delete blog. Check console."
      );
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6 bg-white shadow-lg rounded-lg">
      <h2 className="text-3xl font-semibold mb-6 text-gray-800">
        {editId ? "Edit Blog" : "Add Blog"}
      </h2>

      {error && (
        <p className="mb-4 text-red-600 font-medium bg-red-100 p-3 rounded">
          {error}
        </p>
      )}

      <form onSubmit={handleSubmit} className="space-y-5" encType="multipart/form-data">
        {/* Title */}
        <div>
          <label htmlFor="title" className="block mb-1 font-medium text-gray-700">
            Title
          </label>
          <input
            id="title"
            name="title"
            value={form.title}
            onChange={handleChange}
            placeholder="Enter blog title"
            className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-400"
            required
          />
        </div>

        {/* Full Content */}
        <div>
          <label htmlFor="full_content" className="block mb-1 font-medium text-gray-700">
            Full Content
          </label>
          <textarea
            id="full_content"
            name="full_content"
            value={form.full_content}
            onChange={handleChange}
            placeholder="Enter full detailed content"
            rows={6}
            className="w-full p-3 border border-gray-300 rounded-md resize-none focus:outline-none focus:ring-2 focus:ring-blue-400"
            required
          />
        </div>

        {/* Image Upload */}
        <div>
          <label htmlFor="image" className="block mb-1 font-medium text-gray-700">
            Upload Image
          </label>
          <input
            id="image"
            type="file"
            accept="image/*"
            onChange={handleFileChange}
            className="w-full p-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-400"
          />
        </div>

        {/* User ID & Category ID side by side */}
        <div className="flex space-x-4">
          <div className="flex-1">
            <label htmlFor="user_id" className="block mb-1 font-medium text-gray-700">
              User ID
            </label>
            <input
              id="user_id"
              type="number"
              name="user_id"
              value={form.user_id}
              onChange={handleChange}
              placeholder="User ID"
              className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-400"
              required
              min={1}
            />
          </div>
          <div className="flex-1">
            <label htmlFor="category_id" className="block mb-1 font-medium text-gray-700">
              Category ID
            </label>
            <input
              id="category_id"
              type="number"
              name="category_id"
              value={form.category_id}
              onChange={handleChange}
              placeholder="Category ID"
              className="w-full p-3 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-400"
              required
              min={1}
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={loading}
          className={`w-full py-3 rounded-md text-white font-semibold transition-colors ${
            loading ? "bg-gray-400 cursor-not-allowed" : "bg-blue-600 hover:bg-blue-700"
          }`}
        >
          {editId ? "Update Blog" : "Add Blog"}
        </button>
      </form>

      {/* Blogs Table */}
      <div className="mt-10 overflow-x-auto">
        {loading && <p className="text-center text-gray-600 mb-3">Loading...</p>}

        <table className="min-w-full border border-gray-300 rounded-md">
          <thead className="bg-gray-100">
            <tr>
              <th className="py-3 px-4 border-b text-left">ID</th>
              <th className="py-3 px-4 border-b text-left">Title</th>
              <th className="py-3 px-4 border-b text-left">Category ID</th>
              <th className="py-3 px-4 border-b text-center">Actions</th>
            </tr>
          </thead>
          <tbody>
            {blogs.length === 0 && !loading && (
              <tr>
                <td colSpan="4" className="py-6 text-center text-gray-500">
                  No blogs found.
                </td>
              </tr>
            )}
            {blogs.map((blog) => (
              <tr key={blog.id} className="hover:bg-gray-50">
                <td className="py-2 px-4 border-b">{blog.id}</td>
                <td className="py-2 px-4 border-b">{blog.title}</td>
                <td className="py-2 px-4 border-b text-center">{blog.category_id}</td>
                <td className="py-2 px-4 border-b text-center space-x-2">
                  <button
                    onClick={() => handleEdit(blog)}
                    className="bg-blue-600 hover:bg-blue-700 text-white px-3 py-1 rounded"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(blog.id)}
                    className="bg-red-600 hover:bg-red-700 text-white px-3 py-1 rounded"
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default BlogManage;
